public boolean validateWrite()
{
    boolean ret;

    ret = next validateWrite();

    if(ret && SalesParameters::find().ETGEnableCylinderTracking == NoYes::Yes)
    {
        SalesLine         salesLine         = this.cursor();
        InventTableModule inventTableModule = InventTableModule::find(salesLine.ItemId, ModuleInventPurchSales::Sales);

        // Update: If entity is 'o018', allow None, otherwise enforce mandatory check
        if (salesLine.ETGConnectionType == ETGConnectionType::None && curExt() != 'o018' && curExt() != 'o025')
        {
            ret = checkFailed("@ETG_New:ConnectionTypeMandatoryMsg");
        }

        if (inventTableModule
            && inventTableModule.ETGDepositNeeded == NoYes::Yes
            && inventTableModule.ETGFilledEmptyNeeded == NoYes::Yes
            && salesLine.ETGFilledOrEmpty == ETGFilledOrEmpty::None)
        {
            ret = checkFailed("@ETG_New:FilledEmptyIsMandatoryMsg");
        }
    }

    return ret;
}
